    shift_vowels = {'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
                    'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'}

    encoded_message = []
    for char in message:
        if char.isalpha():
            if char.islower():
                new_char = char.upper()
            else:
                new_char = char.lower()

            if new_char in shift_vowels:
                new_char = shift_vowels[new_char]
        else:
            new_char = char

        encoded_message.append(new_char)

