def check_dict_case(dct):
    if not dct:
        return False

    lower_case_keys = [key for key in dct.keys() if isinstance(key, str) and key.islower()]
    upper_case_keys = [key for key in dct.keys() if isinstance(key, str) and key.isupper()]

    if lower_case_keys and upper_case_keys:
        return False
    elif lower_case_keys:
        return len(lower_case_keys) == len(dct)
    elif upper_case_keys:
        return len(upper_case_keys) == len(dct)
    else:
        return False

