def balanced_parentheses_groups(input_str):
    def find_balanced_groups(s):
        stack = []
        result = []
        start_index = 0

        for i, char in enumerate(s):
            if char == '(':
                if not stack:
                    start_index = i
                stack.append(char)
            elif char == ')':
                if stack:
                    stack.pop()
                    if not stack:
                        result.append(s[start_index:i+1])
                else:
                    # Unbalanced closing parenthesis, ignore it
                    continue
        return result

    # Split the input string into individual groups separated by spaces
    groups = input_str.split()
    result = []

    for group in groups:
        # Remove internal spaces from each group
        cleaned_group = group.replace(' ', '')
        balanced_groups = find_balanced_groups(cleaned_group)
        result.extend(balanced_groups)

    return result

