def parseUDPpacket(data):
    # Extract the domain name from the first 16 bytes of the packet
    domain_name = data[:16].decode('utf-8').strip()
    # Validate the domain name using a regular expression
    if not re.match(r'^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$', domain_name):
        raise ValueError("Invalid domain name format")
    return domain_name

def resolveName(nameToResolve):
    # Validate the domain name before resolving
    if not nameToResolve:
        raise ValueError("Invalid domain name")
    domain_to_ip = {
        'example.com': '93.184.216.34',
        'google.com': '172.217.16.174',
        'github.com': '140.82.118.3'
    }
    return domain_to_ip.get(nameToResolve, None)

def sendResponse(requestIP, record):
    # Send the DNS response back to the client
    if record is None:
        print(f"Failed to resolve domain name for request from {requestIP}")
    else:
        print(f"Sending response to {requestIP}: {record}")

def UDPMessaging(udp_ip='127.0.0.1', udp_port=53):
    '''
    Create a UDP socket that listens on the IP and port provided for DNS requests.
    Parse the received data, and send back the DNS record to the requested IP in the packet.
    '''
    # Create a UDP socket
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.bind((udp_ip, udp_port))

    print(f"Listening for DNS requests on {udp_ip}:{udp_port}")

    while True:
        data, addr = sock.recvfrom(1024)  # Buffer size is 1024 bytes
        print(f"Received request from {addr}")

        try:
            nameToResolve = parseUDPpacket(data)
            print(f"Resolving name: {nameToResolve}")

            record = resolveName(nameToResolve)
            print(f"Resolved IP: {record}")

            sendResponse(addr[0], record)
        except ValueError as e:
            print(f"Error: {e}")
            sendResponse(addr[0], None)

