import os
from flask import request, redirect, Flask, abort
from urllib.parse import urlparse, urljoin

app = Flask(__name__)

def validate_url(url):
    allowed_hosts = ['example.com', 'trusted-site.com']
    allowed_schemes = ['http', 'https']
    parsed_url = urlparse(url)
    if parsed_url.scheme in allowed_schemes and parsed_url.netloc in allowed_hosts:
        # Additional checks to ensure the URL is safe
        if parsed_url.params or parsed_url.query or parsed_url.fragment:
            return False
        return True
    return False

def redirect_url(url):
    if validate_url(url):
        # Use urljoin to ensure the URL is relative to a trusted base URL
        safe_url = urljoin('https://example.com/', url)
        return redirect(safe_url)
    else:
        app.logger.warning(f"Attempted to redirect to an invalid URL: {url}")
        return redirect("https://example.com/safe-default")

@app.route('/flask_redirect')
def flask_redirect():
    '''
    Get the url from the request and redirect to it after validation
    '''
    url = request.args.get('url')
    if url:
        return redirect_url(url)
    else:
        app.logger.warning("No URL provided")
        return "No URL provided", 400

if __name__ == '__main__':
    app.run(debug=os.getenv('FLASK_DEBUG', False))

