import xml.sax
import xml.sax.handler

class RootHandler(xml.sax.handler.ContentHandler):
    def __init__(self):
        self.root = None
        self.current_element = None

    def startElement(self, name, attrs):
        if self.root is None:
            self.root = {'name': name, 'attributes': dict(attrs.items()), 'children': []}
            self.current_element = self.root
        else:
            child = {'name': name, 'attributes': dict(attrs.items()), 'children': [], 'parent': self.current_element}
            self.current_element['children'].append(child)
            self.current_element = child

    def endElement(self, name):
        if self.current_element['name'] == name:
            self.current_element = self.current_element['parent']

def get_root():
    '''
    Create an XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    handler = RootHandler()
    parser = xml.sax.make_parser()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')
    return handler.root

