from flask import Flask, request, jsonify
import re

app = Flask(__name__)

@app.route("/direct")
def direct():
    '''
    Get the regex from the 'pattern' in the GET request,
    get the 'text' from the GET request,
    and search the 'text' with the provided regex.
    '''
    try:
        pattern = request.args.get('pattern')
        text = request.args.get('text')

        if not pattern or not text:
            return jsonify({'error': 'Both pattern and text are required'}), 400

        # Escape the user-provided pattern to prevent regex injection
        safe_pattern = re.escape(pattern)

        match = re.search(safe_pattern, text)
        if match:
            return jsonify({'match': match.group()})
        else:
            return jsonify({'match': None})
    except Exception as e:
        app.logger.error(f"An error occurred: {str(e)}")
        return jsonify({'error': 'An internal error occurred.'}), 500

if __name__ == "__main__":
    app.run(debug=app.config.get('DEBUG', False))

