import requests
from flask import Flask, request
import re
from urllib.parse import urljoin
from jinja2 import Markup  # Import Markup from jinja2

app = Flask(__name__)

# Set debug mode based on environment variable
app.config['DEBUG'] = True  # Change this to False in production

@app.route("/user")
def retrieve_info():
    user_id = request.args.get('user_id')
    if not user_id:
        return "User ID is required", 400

    # Strictly validate user_id to prevent SSRF
    if not re.match(r'^[a-zA-Z0-9\-_]+$', user_id):
        return "Invalid user ID", 400

    # Construct the URL safely
    base_url = "https://api.github.com/users/"
    github_api_url = urljoin(base_url, user_id)

    try:
        response = requests.get(github_api_url, timeout=10)
    except requests.exceptions.Timeout:
        return "Request timed out", 504

    if response.status_code == 200:
        # Escape user input to prevent XSS
        return Markup.escape(response.json())
    else:
        return f"Failed to retrieve user info: {response.status_code}", response.status_code

if __name__ == "__main__":
    app.run(debug=app.config['DEBUG'])

import boto3
from botocore.config import Config

# Assuming `config` is defined elsewhere or you can provide it directly
config = Config(
    region_name='us-west-2',
    retries={
        'max_attempts': 10,
        'mode': 'standard'
    }
)

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)

def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    '''
    response = DYNAMO_CLIENT.get_item(
        TableName='users',
        Key={
            'username': {'S': username},
            'password': {'S': password}
        }
    )

    if 'Item' in response:
        return response['Item']
    else:
        return None
